    [Test]
    [TestCaseSource(nameof(KeyGenVectors))]
    public void KeyGen_MatchesAcvpVector(string parameterSet, int tcId, string skSeedHex, string skPrfHex,
        string pkSeedHex, string pkHex, string skHex)
    {
        SlhDsaParams p = ParamsFor(parameterSet);

        byte[] pk = new byte[p.PublicKeyBytes];
        byte[] sk = new byte[p.SecretKeyBytes];
        SlhDsaCore.KeyGenFromSeeds(p, FromHex(skSeedHex), FromHex(skPrfHex), FromHex(pkSeedHex), pk, sk);

        Assert.That(pk, Is.EqualTo(FromHex(pkHex)), $"{parameterSet} tcId {tcId}: public key mismatch.");
        Assert.That(sk, Is.EqualTo(FromHex(skHex)), $"{parameterSet} tcId {tcId}: secret key mismatch.");
    }

    [Test]
    [TestCaseSource(nameof(SigGenDeterministicVectors))]
    public void SigGenDeterministic_MatchesAcvpVector(string parameterSet, int tcId, string skHex,
        string messageHex, string contextHex, string signatureHex)
    {
        SlhDsaParams p = ParamsFor(parameterSet);
        byte[] sk = FromHex(skHex);

        byte[] context = FromHex(contextHex);
        byte[] prefix = new byte[2 + context.Length];
        MlDsaCore.BuildExternalPrefix(context, prefix);

        // Deterministic signing uses opt_rand = PK.seed (embedded in sk at offset 2n).
        byte[] signature = new byte[p.SignatureBytes];
        SlhDsaCore.Sign(p, sk, prefix, FromHex(messageHex), sk.AsSpan(2 * p.N, p.N), signature);

        Assert.That(signature, Is.EqualTo(FromHex(signatureHex)), $"{parameterSet} tcId {tcId}: signature mismatch.");
    }

    [Test]
    [TestCaseSource(nameof(SigGenHedgedVectors))]
    public void SigGenHedged_MatchesAcvpVector(string parameterSet, int tcId, string skHex,
        string messageHex, string contextHex, string additionalRandomnessHex, string signatureHex)
    {
        SlhDsaParams p = ParamsFor(parameterSet);

        byte[] context = FromHex(contextHex);
        byte[] prefix = new byte[2 + context.Length];
        MlDsaCore.BuildExternalPrefix(context, prefix);

        byte[] signature = new byte[p.SignatureBytes];
        SlhDsaCore.Sign(p, FromHex(skHex), prefix, FromHex(messageHex), FromHex(additionalRandomnessHex), signature);

        Assert.That(signature, Is.EqualTo(FromHex(signatureHex)), $"{parameterSet} tcId {tcId}: signature mismatch.");
    }

    [Test]
    [TestCaseSource(nameof(SigVerVectors))]
    public void SigVer_MatchesAcvpVector(string parameterSet, int tcId, string reason, bool expectedValid,
        string pkHex, string messageHex, string contextHex, string signatureHex)
    {
        using var verifier = CryptoHives.Foundation.Security.Cryptography.Dsa.SlhDsa.ImportPublicKey(
            AlgorithmFor(parameterSet), FromHex(pkHex));

        bool valid = verifier.VerifyData(FromHex(messageHex), FromHex(signatureHex), FromHex(contextHex));

        Assert.That(valid, Is.EqualTo(expectedValid), $"{parameterSet} tcId {tcId} ({reason}): verification result mismatch.");
    }

    private static SlhDsaParams ParamsFor(string parameterSet) => parameterSet switch
    {
        "SLH-DSA-SHA2-128s" => SlhDsaParams.Sha2_128s,
        "SLH-DSA-SHAKE-128s" => SlhDsaParams.Shake128s,
        "SLH-DSA-SHA2-128f" => SlhDsaParams.Sha2_128f,
        "SLH-DSA-SHAKE-128f" => SlhDsaParams.Shake128f,
        "SLH-DSA-SHA2-192s" => SlhDsaParams.Sha2_192s,
        "SLH-DSA-SHAKE-192s" => SlhDsaParams.Shake192s,
        "SLH-DSA-SHA2-192f" => SlhDsaParams.Sha2_192f,
        "SLH-DSA-SHAKE-192f" => SlhDsaParams.Shake192f,
        "SLH-DSA-SHA2-256s" => SlhDsaParams.Sha2_256s,
        "SLH-DSA-SHAKE-256s" => SlhDsaParams.Shake256s,
        "SLH-DSA-SHA2-256f" => SlhDsaParams.Sha2_256f,
        "SLH-DSA-SHAKE-256f" => SlhDsaParams.Shake256f,
        _ => throw new ArgumentException($"Unknown parameter set: {parameterSet}", nameof(parameterSet)),
    };

    private static SlhDsaAlgorithm AlgorithmFor(string parameterSet) => parameterSet switch
    {
        "SLH-DSA-SHA2-128s" => SlhDsaAlgorithm.SlhDsaSha2_128s,
        "SLH-DSA-SHAKE-128s" => SlhDsaAlgorithm.SlhDsaShake128s,
        "SLH-DSA-SHA2-128f" => SlhDsaAlgorithm.SlhDsaSha2_128f,
        "SLH-DSA-SHAKE-128f" => SlhDsaAlgorithm.SlhDsaShake128f,
        "SLH-DSA-SHA2-192s" => SlhDsaAlgorithm.SlhDsaSha2_192s,
        "SLH-DSA-SHAKE-192s" => SlhDsaAlgorithm.SlhDsaShake192s,
        "SLH-DSA-SHA2-192f" => SlhDsaAlgorithm.SlhDsaSha2_192f,
        "SLH-DSA-SHAKE-192f" => SlhDsaAlgorithm.SlhDsaShake192f,
        "SLH-DSA-SHA2-256s" => SlhDsaAlgorithm.SlhDsaSha2_256s,
        "SLH-DSA-SHAKE-256s" => SlhDsaAlgorithm.SlhDsaShake256s,
        "SLH-DSA-SHA2-256f" => SlhDsaAlgorithm.SlhDsaSha2_256f,
        "SLH-DSA-SHAKE-256f" => SlhDsaAlgorithm.SlhDsaShake256f,
        _ => throw new ArgumentException($"Unknown parameter set: {parameterSet}", nameof(parameterSet)),
    };

    private static byte[] FromHex(string hex)
    {
        byte[] bytes = new byte[hex.Length / 2];
        for (int i = 0; i < bytes.Length; i++)
        {
            bytes[i] = Convert.ToByte(hex.Substring(i * 2, 2), 16);
        }

        return bytes;
    }
}
